import subprocess
import os

def generate_requirements_txt():
    """
    Generates a requirements.txt file with hashes using pip.
    """
    subprocess.run(["pip", "freeze", "--all", "--hash=sha256"], stdout=open("requirements.txt", "w"))

def update_requirements_txt():
    """
    Updates the requirements.txt file with the latest dependency versions.
    """
    subprocess.run(["pip-compile", "--upgrade", "--output-file=requirements.txt"])

def generate_poetry_lock():
    """
    Generates a poetry.lock file using Poetry.
    """
    subprocess.run(["poetry", "lock"])

def update_poetry_lock():
    """
    Updates the poetry.lock file with the latest dependency versions.
    """
    subprocess.run(["poetry", "update"])

def ensure_requirements_txt():
    """
    Ensures that requirements.txt exists and is up-to-date.
    """
    if not os.path.exists("requirements.txt"):
        generate_requirements_txt()
    else:
        update_requirements_txt()

def ensure_poetry_lock():
    """
    Ensures that poetry.lock exists and is up-to-date.
    """
    if not os.path.exists("poetry.lock"):
        generate_poetry_lock()
    else:
        update_poetry_lock()

# Example usage
ensure_requirements_txt()  # Uncomment to manage with requirements.txt
